import { render } from 'https://cdn.jsdelivr.net/npm/bit-field@1/+esm';
import { stringify } from 'https://cdn.jsdelivr.net/npm/onml@2/+esm';
const el = document.createElement('div'); el.style.cssText = 'height:200px;overflow:auto'; shadowRoot.appendChild(el);
el.innerHTML = stringify(render(data.fields, data.options ?? {}));

